package com.example.samlsp.config;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

import java.io.FileInputStream;
import java.io.InputStream;
import java.security.KeyStore;
import java.security.PrivateKey;
import java.security.cert.X509Certificate;

@Configuration
public class KeyStoreConfig {

    private final SAMLProperties samlProperties;

    public KeyStoreConfig(SAMLProperties samlProperties) {
        this.samlProperties = samlProperties;
    }

    @Bean
    public KeyStore samlKeyStore() throws Exception {
        KeyStore keyStore = KeyStore.getInstance("JKS");
        try (InputStream is = new FileInputStream(samlProperties.getKeystorePath())) {
            keyStore.load(is, samlProperties.getKeystorePassword().toCharArray());
        }
        return keyStore;
    }

    @Bean
    public X509Certificate spCertificate(KeyStore samlKeyStore) throws Exception {
        return (X509Certificate) samlKeyStore.getCertificate(samlProperties.getKeyAlias());
    }

    @Bean
    public PrivateKey spPrivateKey(KeyStore samlKeyStore) throws Exception {
        return (PrivateKey) samlKeyStore.getKey(
                samlProperties.getKeyAlias(),
                samlProperties.getKeyPassword().toCharArray()
        );
    }
}

