package com.example.samlsp.security;

import org.opensaml.security.credential.Credential;
import org.opensaml.security.credential.BasicCredential;
import org.opensaml.security.x509.BasicX509Credential;
import org.springframework.stereotype.Component;

import java.io.FileInputStream;
import java.io.InputStream;
import java.security.PrivateKey;
import java.security.cert.CertificateFactory;
import java.security.cert.X509Certificate;

import com.example.samlsp.config.SAMLProperties;

@Component
public class SAMLCredentialStore {

    private final X509Certificate spCertificate;
    private final PrivateKey spPrivateKey;
    private final SAMLProperties samlProperties;

    public SAMLCredentialStore(X509Certificate spCertificate, PrivateKey spPrivateKey, SAMLProperties samlProperties) {
        this.spCertificate = spCertificate;
        this.spPrivateKey = spPrivateKey;
        this.samlProperties = samlProperties;
    }

    public Credential getSpSigningCredential() {
        BasicX509Credential credential = new BasicX509Credential(spCertificate, spPrivateKey);
        credential.setEntityId(samlProperties.getEntityId());
        return credential;
    }

    public Credential getIdpVerificationCredential() throws Exception {
        CertificateFactory cf = CertificateFactory.getInstance("X.509");
        X509Certificate idpCert;
        try (InputStream is = new FileInputStream(samlProperties.getIdpCertificatePath())) {
            idpCert = (X509Certificate) cf.generateCertificate(is);
        }
        BasicX509Credential credential = new BasicX509Credential(idpCert);
        credential.setEntityId(samlProperties.getIdpEntityId());
        return credential;
    }
}

