package com.example.samlsp.service;

import com.example.samlsp.config.SAMLProperties;
import com.example.samlsp.security.SAMLCredentialStore;
import org.opensaml.core.xml.XMLObjectBuilderFactory;
import org.opensaml.core.xml.config.XMLObjectProviderRegistrySupport;
import org.opensaml.saml.common.xml.SAMLConstants;
import org.opensaml.saml.saml2.core.*;
import org.opensaml.saml.saml2.core.impl.*;
import org.opensaml.security.credential.Credential;
import org.opensaml.xmlsec.signature.Signature;
import org.opensaml.xmlsec.signature.impl.SignatureBuilder;
import org.opensaml.xmlsec.signature.support.SignatureConstants;
import org.opensaml.xmlsec.signature.support.Signer;
import org.springframework.stereotype.Service;

import javax.xml.namespace.QName;
import java.time.Instant;
import java.util.UUID;

@Service
public class SAMLMessageBuilder {

    private final SAMLProperties samlProperties;
    private final SAMLCredentialStore credentialStore;
    private final XMLObjectBuilderFactory builderFactory;

    public SAMLMessageBuilder(SAMLProperties samlProperties, SAMLCredentialStore credentialStore) {
        this.samlProperties = samlProperties;
        this.credentialStore = credentialStore;
        this.builderFactory = XMLObjectProviderRegistrySupport.getBuilderFactory();
    }

    public AuthnRequest buildAuthnRequest(String relayState) throws Exception {
        AuthnRequest authnRequest = new AuthnRequestBuilder().buildObject();
        authnRequest.setID("_" + UUID.randomUUID().toString());
        authnRequest.setIssueInstant(Instant.now());
        authnRequest.setProtocolBinding(SAMLConstants.SAML2_POST_BINDING_URI);
        authnRequest.setAssertionConsumerServiceURL(samlProperties.getAcsUrl());
        authnRequest.setDestination(samlProperties.getIdpSsoUrl());
        authnRequest.setForceAuthn(false);
        authnRequest.setIsPassive(false);
        authnRequest.setVersion(org.opensaml.saml.common.SAMLVersion.VERSION_20);

        // Issuer
        Issuer issuer = new IssuerBuilder().buildObject();
        issuer.setValue(samlProperties.getEntityId());
        authnRequest.setIssuer(issuer);

        // NameIDPolicy
        NameIDPolicy nameIDPolicy = new NameIDPolicyBuilder().buildObject();
        nameIDPolicy.setFormat(NameIDType.UNSPECIFIED);
        nameIDPolicy.setAllowCreate(true);
        authnRequest.setNameIDPolicy(nameIDPolicy);

        // RequestedAuthnContext
        RequestedAuthnContext requestedAuthnContext = new RequestedAuthnContextBuilder().buildObject();
        requestedAuthnContext.setComparison(AuthnContextComparisonTypeEnumeration.EXACT);

        AuthnContextClassRef authnContextClassRef = new AuthnContextClassRefBuilder().buildObject();
        authnContextClassRef.setURI(AuthnContext.PASSWORD_AUTHN_CTX);
        requestedAuthnContext.getAuthnContextClassRefs().add(authnContextClassRef);
        authnRequest.setRequestedAuthnContext(requestedAuthnContext);

        // Sign the request if configured
        if (samlProperties.isAuthnRequestSigned()) {
            signSAMLObject(authnRequest);
        }

        return authnRequest;
    }

    public LogoutRequest buildLogoutRequest(String nameId, String sessionIndex) throws Exception {
        LogoutRequest logoutRequest = new LogoutRequestBuilder().buildObject();
        logoutRequest.setID("_" + UUID.randomUUID().toString());
        logoutRequest.setIssueInstant(Instant.now());
        logoutRequest.setDestination(samlProperties.getIdpSloUrl());
        logoutRequest.setVersion(org.opensaml.saml.common.SAMLVersion.VERSION_20);

        Issuer issuer = new IssuerBuilder().buildObject();
        issuer.setValue(samlProperties.getEntityId());
        logoutRequest.setIssuer(issuer);

        NameID nameID = new NameIDBuilder().buildObject();
        nameID.setValue(nameId);
        nameID.setFormat(NameIDType.UNSPECIFIED);
        logoutRequest.setNameID(nameID);

        if (sessionIndex != null) {
            SessionIndex sessionIdx = new SessionIndexBuilder().buildObject();
            sessionIdx.setValue(sessionIndex);
            logoutRequest.getSessionIndexes().add(sessionIdx);
        }

        signSAMLObject(logoutRequest);
        return logoutRequest;
    }

    private void signSAMLObject(org.opensaml.saml.common.SignableSAMLObject samlObject) throws Exception {
        Credential credential = credentialStore.getSpSigningCredential();

        Signature signature = new SignatureBuilder().buildObject();
        signature.setSigningCredential(credential);
        signature.setSignatureAlgorithm(SignatureConstants.ALGO_ID_SIGNATURE_RSA_SHA256);
        signature.setCanonicalizationAlgorithm(SignatureConstants.ALGO_ID_C14N_EXCL_OMIT_COMMENTS);

        samlObject.setSignature(signature);

        XMLObjectProviderRegistrySupport.getMarshallerFactory()
                .getMarshaller(samlObject)
                .marshall(samlObject);

        Signer.signObject(signature);
    }
}

