package com.example.samlsp.service;

import com.example.samlsp.config.SAMLProperties;
import com.example.samlsp.security.SAMLCredentialStore;
import org.opensaml.core.xml.XMLObject;
import org.opensaml.core.xml.config.XMLObjectProviderRegistrySupport;
import org.opensaml.core.xml.io.Unmarshaller;
import org.opensaml.core.xml.io.UnmarshallerFactory;
import org.opensaml.core.xml.schema.XSAny;
import org.opensaml.core.xml.schema.XSString;
import org.opensaml.saml.saml2.core.*;
import org.opensaml.security.credential.Credential;
import org.opensaml.xmlsec.signature.Signature;
import org.opensaml.xmlsec.signature.support.SignatureValidator;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;
import org.w3c.dom.Document;
import org.w3c.dom.Element;

import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import java.io.ByteArrayInputStream;
import java.time.Duration;
import java.time.Instant;
import java.util.*;

@Service
public class SAMLResponseValidator {

    private static final Logger logger = LoggerFactory.getLogger(SAMLResponseValidator.class);

    private final SAMLProperties samlProperties;
    private final SAMLCredentialStore credentialStore;

    // Store used SAML response IDs to prevent replay attacks
    private final Set<String> usedResponseIds = Collections.synchronizedSet(new LinkedHashSet<>() {
        @Override
        protected boolean removeEldestEntry(Map.Entry<String, ?> eldest) {
            return size() > 10000;
        }
    });

    // Store used assertion IDs to prevent replay attacks
    private final Set<String> usedAssertionIds = Collections.synchronizedSet(new LinkedHashSet<>() {
        @Override
        protected boolean removeEldestEntry(Map.Entry<String, ?> eldest) {
            return size() > 10000;
        }
    });

    public SAMLResponseValidator(SAMLProperties samlProperties, SAMLCredentialStore credentialStore) {
        this.samlProperties = samlProperties;
        this.credentialStore = credentialStore;
    }

    public SAMLValidationResult validateResponse(String samlResponseBase64) {
        try {
            byte[] decodedBytes = Base64.getDecoder().decode(samlResponseBase64);
            Response response = parseResponse(decodedBytes);

            // 1. Validate response status
            validateStatus(response);

            // 2. Validate response destination
            validateDestination(response);

            // 3. Check for replay attack on response
            validateResponseNotReplayed(response);

            // 4. Validate response signature if present
            if (response.getSignature() != null) {
                validateSignature(response.getSignature());
            }

            // 5. Validate assertions
            List<Assertion> assertions = response.getAssertions();
            if (assertions == null || assertions.isEmpty()) {
                throw new SAMLValidationException("No assertions found in SAML response");
            }

            Assertion assertion = assertions.get(0);

            // 6. Validate assertion signature
            if (samlProperties.isWantAssertionsSigned()) {
                if (assertion.getSignature() == null) {
                    throw new SAMLValidationException("Assertion is not signed but signing is required");
                }
                validateSignature(assertion.getSignature());
            }

            // 7. Check for replay attack on assertion
            validateAssertionNotReplayed(assertion);

            // 8. Validate assertion conditions
            validateConditions(assertion);

            // 9. Validate subject confirmation
            validateSubjectConfirmation(assertion);

            // 10. Validate authentication statement
            validateAuthnStatement(assertion);

            // 11. Validate issuer
            validateIssuer(response.getIssuer());
            validateIssuer(assertion.getIssuer());

            // Extract user information
            String nameId = extractNameId(assertion);
            String sessionIndex = extractSessionIndex(assertion);
            Map<String, List<String>> attributes = extractAttributes(assertion);

            return new SAMLValidationResult(true, nameId, sessionIndex, attributes, null);

        } catch (SAMLValidationException e) {
            logger.error("SAML validation failed: {}", e.getMessage());
            return new SAMLValidationResult(false, null, null, null, e.getMessage());
        } catch (Exception e) {
            logger.error("Unexpected error during SAML validation", e);
            return new SAMLValidationResult(false, null, null, null, "Internal validation error");
        }
    }

    private Response parseResponse(byte[] responseBytes) throws Exception {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);

        // Security: Prevent XXE
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
        factory.setFeature("http://javax.xml.XMLConstants/feature/secure-processing", true);
        factory.setExpandEntityReferences(false);

        DocumentBuilder builder = factory.newDocumentBuilder();
        Document document = builder.parse(new ByteArrayInputStream(responseBytes));
        Element element = document.getDocumentElement();

        UnmarshallerFactory unmarshallerFactory = XMLObjectProviderRegistrySupport.getUnmarshallerFactory();
        Unmarshaller unmarshaller = unmarshallerFactory.getUnmarshaller(element);
        if (unmarshaller == null) {
            throw new SAMLValidationException("Unable to create unmarshaller for SAML response");
        }

        XMLObject xmlObject = unmarshaller.unmarshall(element);
        if (!(xmlObject instanceof Response)) {
            throw new SAMLValidationException("Parsed XML is not a SAML Response");
        }

        return (Response) xmlObject;
    }

    private void validateStatus(Response response) throws SAMLValidationException {
        Status status = response.getStatus();
        if (status == null || status.getStatusCode() == null) {
            throw new SAMLValidationException("SAML response has no status");
        }

        String statusCode = status.getStatusCode().getValue();
        if (!StatusCode.SUCCESS.equals(statusCode)) {
            String message = "SAML authentication failed with status: " + statusCode;
            if (status.getStatusMessage() != null) {
                message += " - " + status.getStatusMessage().getValue();
            }
            throw new SAMLValidationException(message);
        }
    }

    private void validateDestination(Response response) throws SAMLValidationException {
        String destination = response.getDestination();
        if (destination != null && !destination.equals(samlProperties.getAcsUrl())) {
            throw new SAMLValidationException(
                    "Response destination mismatch. Expected: " + samlProperties.getAcsUrl() +
                            ", Got: " + destination);
        }
    }

    private void validateResponseNotReplayed(Response response) throws SAMLValidationException {
        String responseId = response.getID();
        if (responseId == null || responseId.isEmpty()) {
            throw new SAMLValidationException("SAML response has no ID");
        }
        if (!usedResponseIds.add(responseId)) {
            throw new SAMLValidationException("Replay attack detected: Response ID already used: " + responseId);
        }
    }

    private void validateAssertionNotReplayed(Assertion assertion) throws SAMLValidationException {
        String assertionId = assertion.getID();
        if (assertionId == null || assertionId.isEmpty()) {
            throw new SAMLValidationException("SAML assertion has no ID");
        }
        if (!usedAssertionIds.add(assertionId)) {
            throw new SAMLValidationException("Replay attack detected: Assertion ID already used: " + assertionId);
        }
    }

    private void validateSignature(Signature signature) throws Exception {
        Credential idpCredential = credentialStore.getIdpVerificationCredential();
        try {
            SignatureValidator.validate(signature, idpCredential);
        } catch (Exception e) {
            throw new SAMLValidationException("Signature validation failed: " + e.getMessage());
        }
    }

    private void validateConditions(Assertion assertion) throws SAMLValidationException {
        Conditions conditions = assertion.getConditions();
        if (conditions == null) {
            throw new SAMLValidationException("Assertion has no conditions");
        }

        Instant now = Instant.now();
        int skewSeconds = samlProperties.getResponseSkew();

        // Validate NotBefore
        Instant notBefore = conditions.getNotBefore();
        if (notBefore != null) {
            if (now.plus(Duration.ofSeconds(skewSeconds)).isBefore(notBefore)) {
                throw new SAMLValidationException("Assertion is not yet valid. NotBefore: " + notBefore);
            }
        }

        // Validate NotOnOrAfter
        Instant notOnOrAfter = conditions.getNotOnOrAfter();
        if (notOnOrAfter != null) {
            if (now.minus(Duration.ofSeconds(skewSeconds)).isAfter(notOnOrAfter) || now.equals(notOnOrAfter)) {
                throw new SAMLValidationException("Assertion has expired. NotOnOrAfter: " + notOnOrAfter);
            }
        }

        // Validate AudienceRestriction
        List<AudienceRestriction> audienceRestrictions = conditions.getAudienceRestrictions();
        if (audienceRestrictions != null && !audienceRestrictions.isEmpty()) {
            boolean audienceMatch = false;
            for (AudienceRestriction restriction : audienceRestrictions) {
                for (Audience audience : restriction.getAudiences()) {
                    if (samlProperties.getEntityId().equals(audience.getURI())) {
                        audienceMatch = true;
                        break;
                    }
                }
                if (audienceMatch) break;
            }
            if (!audienceMatch) {
                throw new SAMLValidationException("SP entity ID not found in audience restrictions");
            }
        }
    }

    private void validateSubjectConfirmation(Assertion assertion) throws SAMLValidationException {
        Subject subject = assertion.getSubject();
        if (subject == null) {
            throw new SAMLValidationException("Assertion has no subject");
        }

        List<SubjectConfirmation> confirmations = subject.getSubjectConfirmations();
        if (confirmations == null || confirmations.isEmpty()) {
            throw new SAMLValidationException("No subject confirmations found");
        }

        boolean validConfirmation = false;
        Instant now = Instant.now();
        int skewSeconds = samlProperties.getResponseSkew();

        for (SubjectConfirmation confirmation : confirmations) {
            if (SubjectConfirmation.METHOD_BEARER.equals(confirmation.getMethod())) {
                SubjectConfirmationData data = confirmation.getSubjectConfirmationData();
                if (data != null) {
                    // Validate NotOnOrAfter
                    if (data.getNotOnOrAfter() != null) {
                        if (now.minus(Duration.ofSeconds(skewSeconds)).isAfter(data.getNotOnOrAfter())) {
                            continue;
                        }
                    }

                    // Validate Recipient
                    if (data.getRecipient() != null && !data.getRecipient().equals(samlProperties.getAcsUrl())) {
                        continue;
                    }

                    // Validate NotBefore
                    if (data.getNotBefore() != null) {
                        if (now.plus(Duration.ofSeconds(skewSeconds)).isBefore(data.getNotBefore())) {
                            continue;
                        }
                    }

                    validConfirmation = true;
                    break;
                }
            }
        }

        if (!validConfirmation) {
            throw new SAMLValidationException("No valid subject confirmation found");
        }
    }

    private void validateAuthnStatement(Assertion assertion) throws SAMLValidationException {
        List<AuthnStatement> authnStatements = assertion.getAuthnStatements();
        if (authnStatements == null || authnStatements.isEmpty()) {
            throw new SAMLValidationException("No authentication statements found");
        }

        AuthnStatement authnStatement = authnStatements.get(0);
        Instant authnInstant = authnStatement.getAuthnInstant();
        if (authnInstant != null) {
            Instant maxAge = Instant.now().minus(Duration.ofSeconds(samlProperties.getMaxAuthenticationAge()));
            if (authnInstant.isBefore(maxAge)) {
                throw new SAMLValidationException("Authentication is too old. AuthnInstant: " + authnInstant);
            }
        }

        // Validate session expiry if present
        Instant sessionNotOnOrAfter = authnStatement.getSessionNotOnOrAfter();
        if (sessionNotOnOrAfter != null && Instant.now().isAfter(sessionNotOnOrAfter)) {
            throw new SAMLValidationException("Session has expired. SessionNotOnOrAfter: " + sessionNotOnOrAfter);
        }
    }

    private void validateIssuer(Issuer issuer) throws SAMLValidationException {
        if (issuer == null || issuer.getValue() == null) {
            throw new SAMLValidationException("Issuer is missing");
        }
        if (!samlProperties.getIdpEntityId().equals(issuer.getValue())) {
            throw new SAMLValidationException(
                    "Issuer mismatch. Expected: " + samlProperties.getIdpEntityId() +
                            ", Got: " + issuer.getValue());
        }
    }

    private String extractNameId(Assertion assertion) throws SAMLValidationException {
        Subject subject = assertion.getSubject();
        if (subject == null || subject.getNameID() == null) {
            throw new SAMLValidationException("NameID not found in assertion");
        }
        return subject.getNameID().getValue();
    }

    private String extractSessionIndex(Assertion assertion) {
        List<AuthnStatement> authnStatements = assertion.getAuthnStatements();
        if (authnStatements != null && !authnStatements.isEmpty()) {
            return authnStatements.get(0).getSessionIndex();
        }
        return null;
    }

    private Map<String, List<String>> extractAttributes(Assertion assertion) {
        Map<String, List<String>> attributeMap = new HashMap<>();

        List<AttributeStatement> attributeStatements = assertion.getAttributeStatements();
        if (attributeStatements != null) {
            for (AttributeStatement statement : attributeStatements) {
                for (Attribute attribute : statement.getAttributes()) {
                    String name = attribute.getName();
                    List<String> values = new ArrayList<>();
                    for (XMLObject value : attribute.getAttributeValues()) {
                        if (value instanceof XSString) {
                            values.add(((XSString) value).getValue());
                        } else if (value instanceof XSAny) {
                            values.add(((XSAny) value).getTextContent());
                        } else {
                            values.add(value.toString());
                        }
                    }
                    attributeMap.put(name, values);
                }
            }
        }

        return attributeMap;
    }
}

