package com.example.samlsp.service;

import org.opensaml.core.xml.XMLObject;
import org.opensaml.core.xml.config.XMLObjectProviderRegistrySupport;
import org.opensaml.core.xml.io.Marshaller;
import org.opensaml.core.xml.io.MarshallerFactory;
import org.springframework.stereotype.Service;
import org.w3c.dom.Element;

import javax.xml.transform.Transformer;
import javax.xml.transform.TransformerFactory;
import javax.xml.transform.dom.DOMSource;
import javax.xml.transform.stream.StreamResult;
import java.io.ByteArrayOutputStream;
import java.io.StringWriter;
import java.net.URLEncoder;
import java.nio.charset.StandardCharsets;
import java.util.Base64;
import java.util.zip.Deflater;
import java.util.zip.DeflaterOutputStream;

@Service
public class SAMLEncodingService {

    public String encodeForPost(XMLObject samlObject) throws Exception {
        String xmlString = marshallToString(samlObject);
        return Base64.getEncoder().encodeToString(xmlString.getBytes(StandardCharsets.UTF_8));
    }

    public String encodeForRedirect(XMLObject samlObject) throws Exception {
        String xmlString = marshallToString(samlObject);

        ByteArrayOutputStream bytesOut = new ByteArrayOutputStream();
        Deflater deflater = new Deflater(Deflater.DEFLATED, true);
        DeflaterOutputStream deflaterStream = new DeflaterOutputStream(bytesOut, deflater);
        deflaterStream.write(xmlString.getBytes(StandardCharsets.UTF_8));
        deflaterStream.finish();

        String base64 = Base64.getEncoder().encodeToString(bytesOut.toByteArray());
        return URLEncoder.encode(base64, StandardCharsets.UTF_8.name());
    }

    private String marshallToString(XMLObject samlObject) throws Exception {
        MarshallerFactory marshallerFactory = XMLObjectProviderRegistrySupport.getMarshallerFactory();
        Marshaller marshaller = marshallerFactory.getMarshaller(samlObject);
        if (marshaller == null) {
            throw new RuntimeException("Unable to get marshaller for SAML object");
        }

        Element element = marshaller.marshall(samlObject);

        TransformerFactory transformerFactory = TransformerFactory.newInstance();
        // Security: Prevent XXE in transformer
        transformerFactory.setFeature("http://javax.xml.XMLConstants/feature/secure-processing", true);
        transformerFactory.setAttribute("http://javax.xml.XMLConstants/property/accessExternalDTD", "");
        transformerFactory.setAttribute("http://javax.xml.XMLConstants/property/accessExternalStylesheet", "");

        Transformer transformer = transformerFactory.newTransformer();
        StringWriter writer = new StringWriter();
        transformer.transform(new DOMSource(element), new StreamResult(writer));
        return writer.toString();
    }
}

