// ============================================================
package com.example.samlsp.service;

import com.example.samlsp.config.SAMLProperties;
import org.opensaml.core.xml.config.XMLObjectProviderRegistrySupport;
import org.opensaml.core.xml.io.Marshaller;
import org.opensaml.saml.common.xml.SAMLConstants;
import org.opensaml.saml.saml2.metadata.*;
import org.opensaml.saml.saml2.metadata.impl.*;
import org.opensaml.security.credential.UsageType;
import org.opensaml.xmlsec.signature.KeyInfo;
import org.opensaml.xmlsec.signature.X509Certificate;
import org.opensaml.xmlsec.signature.X509Data;
import org.opensaml.xmlsec.signature.impl.KeyInfoBuilder;
import org.opensaml.xmlsec.signature.impl.X509CertificateBuilder;
import org.opensaml.xmlsec.signature.impl.X509DataBuilder;
import org.springframework.stereotype.Service;
import org.w3c.dom.Element;

import javax.xml.transform.Transformer;
import javax.xml.transform.TransformerFactory;
import javax.xml.transform.dom.DOMSource;
import javax.xml.transform.stream.StreamResult;
import java.io.StringWriter;
import java.util.Base64;

@Service
public class SAMLMetadataService {

    private final SAMLProperties samlProperties;
    private final java.security.cert.X509Certificate spCertificate;

    public SAMLMetadataService(SAMLProperties samlProperties, java.security.cert.X509Certificate spCertificate) {
        this.samlProperties = samlProperties;
        this.spCertificate = spCertificate;
    }

    public String generateMetadata() throws Exception {
        EntityDescriptor entityDescriptor = new EntityDescriptorBuilder().buildObject();
        entityDescriptor.setEntityID(samlProperties.getEntityId());

        SPSSODescriptor spssoDescriptor = new SPSSODescriptorBuilder().buildObject();
        spssoDescriptor.setWantAssertionsSigned(samlProperties.isWantAssertionsSigned());
        spssoDescriptor.setAuthnRequestsSigned(samlProperties.isAuthnRequestSigned());
        spssoDescriptor.addSupportedProtocol(SAMLConstants.SAML20P_NS);

        // Signing key descriptor
        KeyDescriptor signingKeyDescriptor = buildKeyDescriptor(UsageType.SIGNING);
        spssoDescriptor.getKeyDescriptors().add(signingKeyDescriptor);

        // Encryption key descriptor
        KeyDescriptor encryptionKeyDescriptor = buildKeyDescriptor(UsageType.ENCRYPTION);
        spssoDescriptor.getKeyDescriptors().add(encryptionKeyDescriptor);

        // NameID formats
        NameIDFormat nameIDFormat = new NameIDFormatBuilder().buildObject();
        nameIDFormat.setURI("urn:oasis:names:tc:SAML:1.1:nameid-format:unspecified");
        spssoDescriptor.getNameIDFormats().add(nameIDFormat);

        NameIDFormat emailFormat = new NameIDFormatBuilder().buildObject();
        emailFormat.setURI("urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress");
        spssoDescriptor.getNameIDFormats().add(emailFormat);

        // ACS endpoint (POST binding)
        AssertionConsumerService acsPost = new AssertionConsumerServiceBuilder().buildObject();
        acsPost.setBinding(SAMLConstants.SAML2_POST_BINDING_URI);
        acsPost.setLocation(samlProperties.getAcsUrl());
        acsPost.setIndex(0);
        acsPost.setIsDefault(true);
        spssoDescriptor.getAssertionConsumerServices().add(acsPost);

        // SLO endpoint
        if (samlProperties.getSloUrl() != null) {
            SingleLogoutService sloPost = new SingleLogoutServiceBuilder().buildObject();
            sloPost.setBinding(SAMLConstants.SAML2_POST_BINDING_URI);
            sloPost.setLocation(samlProperties.getSloUrl());
            spssoDescriptor.getSingleLogoutServices().add(sloPost);

            SingleLogoutService sloRedirect = new SingleLogoutServiceBuilder().buildObject();
            sloRedirect.setBinding(SAMLConstants.SAML2_REDIRECT_BINDING_URI);
            sloRedirect.setLocation(samlProperties.getSloUrl());
            spssoDescriptor.getSingleLogoutServices().add(sloRedirect);
        }

        entityDescriptor.getRoleDescriptors().add(spssoDescriptor);

        // Marshall to XML string
        Marshaller marshaller = XMLObjectProviderRegistrySupport.getMarshallerFactory()
                .getMarshaller(entityDescriptor);
        Element element = marshaller.marshall(entityDescriptor);

        TransformerFactory transformerFactory = TransformerFactory.newInstance();
        transformerFactory.setFeature("http://javax.xml.XMLConstants/feature/secure-processing", true);
        transformerFactory.setAttribute("http://javax.xml.XMLConstants/property/accessExternalDTD", "");
        transformerFactory.setAttribute("http://javax.xml.XMLConstants/property/accessExternalStylesheet", "");

        Transformer transformer = transformerFactory.newTransformer();
        StringWriter writer = new StringWriter();
        transformer.transform(new DOMSource(element), new StreamResult(writer));
        return writer.toString();
    }

    private KeyDescriptor buildKeyDescriptor(UsageType usageType) throws Exception {
        KeyDescriptor keyDescriptor = new KeyDescriptorBuilder().buildObject();
        keyDescriptor.setUse(usageType);

        KeyInfo keyInfo = new KeyInfoBuilder().buildObject();
        X509Data x509Data = new X509DataBuilder().buildObject();
        X509Certificate x509Certificate = new X509CertificateBuilder().buildObject();

        String certBase64 = Base64.getEncoder().encodeToString(spCertificate.getEncoded());
        x509Certificate.setValue(certBase64);

        x509Data.getX509Certificates().add(x509Certificate);
        keyInfo.getX509Datas().add(x509Data);
        keyDescriptor.setKeyInfo(keyInfo);

        return keyDescriptor;
    }
}

