package com.example.samlsp.service;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

@Service
public class SAMLSessionService {

    private static final Logger logger = LoggerFactory.getLogger(SAMLSessionService.class);

    // Maps session index to HTTP session ID
    private final Map<String, String> sessionIndexMap = new ConcurrentHashMap<>();
    // Maps request ID to relay state for InResponseTo validation
    private final Map<String, String> pendingRequests = new ConcurrentHashMap<>();

    public void registerSession(String sessionIndex, String httpSessionId) {
        if (sessionIndex != null && httpSessionId != null) {
            sessionIndexMap.put(sessionIndex, httpSessionId);
            logger.debug("Registered SAML session: {} -> {}", sessionIndex, httpSessionId);
        }
    }

    public String getHttpSessionId(String sessionIndex) {
        return sessionIndexMap.get(sessionIndex);
    }

    public void removeSession(String sessionIndex) {
        if (sessionIndex != null) {
            sessionIndexMap.remove(sessionIndex);
            logger.debug("Removed SAML session: {}", sessionIndex);
        }
    }

    public void storePendingRequest(String requestId, String relayState) {
        pendingRequests.put(requestId, relayState != null ? relayState : "");
    }

    public String getPendingRelayState(String requestId) {
        return pendingRequests.remove(requestId);
    }
}

