// filter/SAMLAuthenticationFilter.java
// ============================================================
package com.example.samlsp.filter;

import com.example.samlsp.security.SAMLAuthenticationToken;
import com.example.samlsp.security.SAMLUserDetails;
import com.example.samlsp.service.SAMLResponseValidator;
import com.example.samlsp.service.SAMLSessionService;
import com.example.samlsp.service.SAMLValidationResult;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.web.filter.OncePerRequestFilter;

import javax.servlet.FilterChain;
import javax.servlet.ServletException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import javax.servlet.http.HttpSession;
import java.io.IOException;
import java.util.Collections;
import java.util.List;

public class SAMLAuthenticationFilter extends OncePerRequestFilter {

    private static final Logger logger = LoggerFactory.getLogger(SAMLAuthenticationFilter.class);

    private final SAMLResponseValidator responseValidator;
    private final SAMLSessionService sessionService;
    private final String acsPath;

    public SAMLAuthenticationFilter(SAMLResponseValidator responseValidator,
                                    SAMLSessionService sessionService,
                                    String acsPath) {
        this.responseValidator = responseValidator;
        this.sessionService = sessionService;
        this.acsPath = acsPath;
    }

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response,
                                    FilterChain filterChain) throws ServletException, IOException {

        if (isAcsRequest(request)) {
            handleAcsRequest(request, response);
            return;
        }

        filterChain.doFilter(request, response);
    }

    private boolean isAcsRequest(HttpServletRequest request) {
        return "POST".equalsIgnoreCase(request.getMethod()) &&
                request.getRequestURI().endsWith(acsPath);
    }

    private void handleAcsRequest(HttpServletRequest request, HttpServletResponse response)
            throws IOException {

        String samlResponse = request.getParameter("SAMLResponse");
        String relayState = request.getParameter("RelayState");

        if (samlResponse == null || samlResponse.isEmpty()) {
            logger.error("No SAMLResponse parameter found in ACS request");
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Missing SAMLResponse");
            return;
        }

        SAMLValidationResult result = responseValidator.validateResponse(samlResponse);

        if (!result.isValid()) {
            logger.error("SAML response validation failed: {}", result.getErrorMessage());
            response.sendError(HttpServletResponse.SC_UNAUTHORIZED, "SAML authentication failed");
            return;
        }

        // Create authenticated user
        List<SimpleGrantedAuthority> authorities = Collections.singletonList(
                new SimpleGrantedAuthority("ROLE_USER"));

        SAMLUserDetails userDetails = new SAMLUserDetails(
                result.getNameId(),
                result.getNameId(),
                result.getSessionIndex(),
                result.getAttributes(),
                authorities
        );

        SAMLAuthenticationToken authToken = new SAMLAuthenticationToken(userDetails, authorities);
        SecurityContextHolder.getContext().setAuthentication(authToken);

        // Create new session to prevent session fixation
        HttpSession oldSession = request.getSession(false);
        if (oldSession != null) {
            oldSession.invalidate();
        }
        HttpSession newSession = request.getSession(true);

        // Register SAML session
        sessionService.registerSession(result.getSessionIndex(), newSession.getId());

        // Store authentication in session
        newSession.setAttribute("SPRING_SECURITY_CONTEXT", SecurityContextHolder.getContext());

        // Redirect to relay state or default page
        String redirectUrl = (relayState != null && !relayState.isEmpty()) ? relayState : "/";

        // Validate redirect URL to prevent open redirect
        if (!isValidRedirectUrl(redirectUrl)) {
            redirectUrl = "/";
        }

        response.sendRedirect(redirectUrl);
    }

    private boolean isValidRedirectUrl(String url) {
        // Only allow relative URLs to prevent open redirect attacks
        return url != null && url.startsWith("/") && !url.startsWith("//");
    }
}

// ============================================================
// filter/CSRFProtectionFilter.java
// ============================================================
package com.example.samlsp.filter;

import org.springframework.web.filter.OncePerRequestFilter;

import javax.servlet.FilterChain;
import javax.servlet.ServletException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.io.IOException;
import java.security.SecureRandom;
import java.util.Base64;

public class CSRFProtectionFilter extends OncePerRequestFilter {

    private static final String CSRF_TOKEN_ATTR = "CSRF_TOKEN";
    private static final String CSRF_TOKEN_HEADER = "X-CSRF-Token";
    private static final String CSRF_TOKEN_PARAM = "_csrf";
    private static final SecureRandom secureRandom = new SecureRandom();

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response,
                                    FilterChain filterChain) throws ServletException, IOException {

        // Skip CSRF for SAML ACS endpoint (POST from IdP)
        if (request.getRequestURI().contains("/saml/acs")) {
            filterChain.doFilter(request, response);
            return;
        }

        String method = request.getMethod();
        if ("POST".equals(method) || "PUT".equals(method) || "DELETE".equals(method) || "PATCH".equals(method)) {
            String sessionToken = (String) request.getSession().getAttribute(CSRF_TOKEN_ATTR);
            String requestToken = request.getHeader(CSRF_TOKEN_HEADER);
            if (requestToken == null) {
                requestToken = request.getParameter(CSRF_TOKEN_PARAM);
            }

            if (sessionToken == null || !sessionToken.equals(requestToken)) {
                response.sendError(HttpServletResponse.SC_FORBIDDEN, "CSRF token validation failed");
                return;
            }
        }

        // Generate CSRF token if not present
        if (request.getSession().getAttribute(CSRF_TOKEN_ATTR) == null) {
            byte[] tokenBytes = new byte[32];
            secureRandom.nextBytes(tokenBytes);
            String token = Base64.getUrlEncoder().withoutPadding().encodeToString(tokenBytes);
            request.getSession().setAttribute(CSRF_TOKEN_ATTR, token);
        }

        filterChain.doFilter(request, response);
    }
}

