// config/SecurityConfig.java
// ============================================================
package com.example.samlsp.config;

import com.example.samlsp.filter.CSRFProtectionFilter;
import com.example.samlsp.filter.SAMLAuthenticationFilter;
import com.example.samlsp.service.SAMLResponseValidator;
import com.example.samlsp.service.SAMLSessionService;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.annotation.web.configuration.WebSecurityConfigurerAdapter;
import org.springframework.security.config.http.SessionCreationPolicy;
import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;
import org.springframework.security.web.header.writers.ReferrerPolicyHeaderWriter;

@Configuration
@EnableWebSecurity
public class SecurityConfig extends WebSecurityConfigurerAdapter {

    private final SAMLResponseValidator responseValidator;
    private final SAMLSessionService sessionService;
    private final SAMLProperties samlProperties;

    public SecurityConfig(SAMLResponseValidator responseValidator,
                          SAMLSessionService sessionService,
                          SAMLProperties samlProperties) {
        this.responseValidator = responseValidator;
        this.sessionService = sessionService;
        this.samlProperties = samlProperties;
    }

    @Override
    protected void configure(HttpSecurity http) throws Exception {
        http
            // Disable default CSRF since we handle SAML POST specially
            .csrf().disable()

            // Session management
            .sessionManagement()
                .sessionCreationPolicy(SessionCreationPolicy.IF_REQUIRED)
                .sessionFixation().newSession()
                .maximumSessions(1)
                .and()
            .and()

            // Security headers
            .headers()
                .contentSecurityPolicy("default-src 'self'; script-src 'self'; style-src 'self'; img-src 'self' data:; font-src 'self'; frame-ancestors 'none'; form-action 'self' " + samlProperties.getIdpSsoUrl())
                .and()
                .frameOptions().deny()
                .xssProtection().block(true)
                .and()
                .contentTypeOptions()
                .and()
                .httpStrictTransportSecurity()
                    .includeSubDomains(true)
                    .maxAgeInSeconds(31536000)
                .and()
                .referrerPolicy(ReferrerPolicyHeaderWriter.ReferrerPolicy.STRICT_ORIGIN_WHEN_CROSS_ORIGIN)
                .and()
                .permissionsPolicy(permissions -> permissions.policy(
                    "camera=(), microphone=(), geolocation=(), payment=()"
                ))
            .and()

            // Authorization rules
            .authorizeRequests()
                .antMatchers("/saml/**").permitAll()
                .antMatchers("/health").permitAll()
                .antMatchers("/error").permitAll()
                .anyRequest().authenticated()
            .and()

            // Add SAML authentication filter
            .addFilterBefore(samlAuthenticationFilter(), UsernamePasswordAuthenticationFilter.class)
            .addFilterAfter(new CSRFProtectionFilter(), SAMLAuthenticationFilter.class)

            // Logout
            .logout()
                .logoutUrl("/logout")
                .logoutSuccessUrl("/saml/logout")
                .invalidateHttpSession(true)
                .clearAuthentication(true)
                .deleteCookies("JSESSIONID");
    }

    @Bean
    public SAMLAuthenticationFilter samlAuthenticationFilter() {
        return new SAMLAuthenticationFilter(responseValidator, sessionService, "/saml/acs");
    }
}

